# ---------------------------------------------------------------------------
# PDF builder
# ---------------------------------------------------------------------------


def _build_pdf_bytes(title: str, text_lines: List[str]) -> bytes:
    """Build a minimal PDF 1.4 with the given lines
    embedded as text. The text is rendered with
    /F1 (Helvetica) at 12pt, each line 20pt below
    the previous, starting at (50, 750).

    The xref offsets are computed programmatically
    (not hand-stamped) so the builder scales to
    different text lengths.
    """
    # Build the content stream first so we can measure
    # its length and the object offsets.
    content_ops = ["BT", "/F1 12 Tf", "50 750 Td"]
    for i, line in enumerate(text_lines):
        # PDF text strings: escape ( ) \ and use \n for newlines
        escaped = (
            line.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
        )
        if i == 0:
            content_ops.append(f"({escaped}) Tj")
        else:
            content_ops.append("0 -20 Td")
            content_ops.append(f"({escaped}) Tj")
    content_ops.append("ET")
    content_stream = "\n".join(content_ops) + "\n"
    # PDF text strings are byte strings; the existing
    # hand-stamped fixture (test_drawing_ingest_e2e.py::
    # MINIMAL_PDF_BYTES) uses latin-1 for special characters
    # like Ø (U+00D8). We match that here so pdfplumber
    # round-trips the dimension annotations correctly.
    content_bytes = content_stream.encode("latin-1")

    # Now build the object table. Track byte offsets
    # so we can write the xref table correctly.
    objects: List[bytes] = []

    def add(obj_bytes: bytes) -> int:
        """Append an object and return its 1-based id."""
        objects.append(obj_bytes)
        return len(objects)

    catalog_id = add(b"<< /Type /Catalog /Pages 2 0 R >>")
    pages_id = add(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
    page_id = add(
        b"<< /Type /Page /Parent 2 0 R "
        b"/MediaBox [0 0 612 792] "
        b"/Contents 4 0 R "
        b"/Resources << /Font << /F1 5 0 R >> >> >>"
    )
    content_obj = (
        f"<< /Length {len(content_bytes)} >>\nstream\n".encode("ascii")
        + content_bytes
        + b"endstream"
    )
    content_id = add(content_obj)
    font_id = add(b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>")

    # Compose the file body, capturing object offsets
    # for the xref table.
    body = b"%PDF-1.4\n"
    offsets: Dict[int, int] = {}
    for idx, obj_bytes in enumerate(objects, start=1):
        offsets[idx] = len(body)
        body += f"{idx} 0 obj\n".encode("ascii") + obj_bytes + b"\nendobj\n"

    xref_offset = len(body)
    xref_lines = [f"xref\n0 {len(objects) + 1}\n",
                  "0000000000 65535 f \n"]
    for idx in range(1, len(objects) + 1):
        xref_lines.append(f"{offsets[idx]:010d} 00000 n \n")
    body += "".join(xref_lines).encode("ascii")
    body += (
        f"trailer\n<< /Size {len(objects) + 1} /Root 1 0 R >>\n"
        f"startxref\n{xref_offset}\n%%EOF\n"
    ).encode("ascii")

    return body


def _fixture_text_lines(fixture: Dict) -> List[str]:
    """Return the text lines to embed in a fixture PDF,
    shaped to trigger the OCR pipeline's parsers."""
    lines = [
        f"TITLE: {fixture['title']}",
        f"DWG.NO: {fixture['drawing_number']}",
        f"REV: A",
        f"MATERIAL: {fixture['material']}",
        f"DATE: 11/06/2026",
        "",
        "BILL OF MATERIALS:",
    ]
    lines.extend(fixture["bom_lines"])
    lines.append("")
    lines.append("DIMENSIONS:")
    lines.extend(fixture["dimension_lines"])
    return lines


# ---------------------------------------------------------------------------
# Sidecar builders
# ---------------------------------------------------------------------------


def _expected_graph(fixture: Dict) -> Dict:
    """The canonical MachineGraph the platform must
    produce for this fixture. Single-node graph
    (one subsystem per fixture) in the dict shape
    produced by ``SubsystemNode.to_dict()``.

    The regression test asserts the platform's actual
    graph is a **superset** of this sidecar's
    node_id keys (over-extraction allowed;
    under-extraction fails per spec §5.1).
    """
    node_id = fixture["name"]
    return {
        "name": fixture["title"].replace(" A3 SHEET 1", "").lower().replace(" ", "_"),
        "revision": "A",
        "nodes": {
            node_id: {
                "node_id": node_id,
                "node_type": node_id,
                "label": fixture["subsystem_keyword"],
                "config": {},
                "source": "drawing",
                "confidence": 0.85,
                "metadata": {},
            },
        },
        "edges": [],
    }


def _expected_score_placeholder() -> str:
    """The placeholder score sidecar. The maintainer
    must run the manual reference config through
    the orchestrator and replace this with the
    actual composite score minus 0.10 per spec §5.1.
    """
    return (
        "TBD\n"
        "# The maintainer must run the manual reference config\n"
        "# for this subsystem through the orchestrator and record\n"
        "# the composite score minus 0.10 per spec §5.1.\n"
        "# See docs/VALIDATION_PACK_METHODOLOGY.md for the\n"
        "# baselining protocol.\n"
    )


# ---------------------------------------------------------------------------
# Driver
# ---------------------------------------------------------------------------


def build_pack(target_dir: Path) -> int:
    """Build the 6 PDFs and 6 sidecar pairs in
    ``target_dir``. Returns the number of fixture
    files written (PDFs + sidecars = 18 total).
    """
    target_dir.mkdir(parents=True, exist_ok=True)
    expected_dir = target_dir / "expected"
    expected_dir.mkdir(parents=True, exist_ok=True)

    written = 0
    for fixture in _SUBSYSTEM_FIXTURES:
        # Write the PDF.
        pdf_bytes = _build_pdf_bytes(
            fixture["title"],
            _fixture_text_lines(fixture),
        )
        pdf_path = target_dir / fixture["filename"]
        pdf_path.write_bytes(pdf_bytes)
        written += 1

        # Write the graph sidecar.
        graph_path = expected_dir / f"{fixture['name']}_a3.graph.json"
        graph_path.write_text(
            json.dumps(_expected_graph(fixture), indent=2)
            + "\n",
            encoding="utf-8",
        )
        written += 1

        # Write the score sidecar (placeholder).
        score_path = expected_dir / f"{fixture['name']}_a3.score.txt"
        score_path.write_text(
            _expected_score_placeholder(),
            encoding="utf-8",
        )
        written += 1

    return written


def main() -> int:
    """CLI entry point. Build the pack in
    ``tests/fixtures/drawings/`` (relative to the
    repository root)."""
    repo_root = Path(__file__).resolve().parents[2]
    target_dir = repo_root / "tests" / "fixtures" / "drawings"

    if not repo_root.exists():
        print(f"error: repo root not found at {repo_root}", file=sys.stderr)
        return 1

    written = build_pack(target_dir)
    print(
        f"Validation pack built: {written} files in {target_dir.relative_to(repo_root)}/"
    )
    print(
        "Note: expected/*_a3.score.txt files contain 'TBD' "
        "placeholders. The maintainer must baseline them by "
        "running the manual reference configs through the "
        "orchestrator per docs/VALIDATION_PACK_METHODOLOGY.md."
    )
    return 0


if __name__ == "__main__":
    sys.exit(main())
